package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"runtime"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// Constants to limit resource consumption.
const (
	maxRequestBodySize = 1 << 20 // 1 MB
	maxResponseSize    = 2 << 20 // 2 MB
	maxRedirects       = 10
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// defaultClient is a reusable fasthttp client with reasonable limits.
var defaultClient = &fasthttp.Client{
	Dial:                fasthttp.DialDualStack,
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 10 * time.Second,
	MaxConnsPerHost:     10,
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method.
	if !ctx.IsPost() {
		resp := PreviewResponse{Error: "Method not allowed"}
		writeJSONError(ctx, resp, fasthttp.StatusMethodNotAllowed)
		return
	}

	// Enforce request content type.
	ctype := string(ctx.Request.Header.ContentType())
	if !strings.Contains(ctype, "application/json") {
		resp := PreviewResponse{Error: "Content-Type must be application/json"}
		writeJSONError(ctx, resp, fasthttp.StatusUnsupportedMediaType)
		return
	}

	// Limit request body size.
	body := ctx.PostBody()
	if len(body) > maxRequestBodySize {
		resp := PreviewResponse{Error: "Request body too large"}
		writeJSONError(ctx, resp, fasthttp.StatusRequestEntityTooLarge)
		return
	}

	// Parse JSON request.
	var req struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(body, &req); err != nil {
		resp := PreviewResponse{Error: "Invalid JSON"}
		writeJSONError(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		resp := PreviewResponse{Error: "URL is required"}
		writeJSONError(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format and scheme.
	parsedURL, err := url.Parse(targetURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		resp := PreviewResponse{Error: "Invalid URL format"}
		writeJSONError(ctx, resp, fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		resp := PreviewResponse{Error: "URL must use http or https scheme"}
		writeJSONError(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// SSRF protection: ensure the host does not resolve to a private or disallowed IP.
	if err := checkHostAllowed(targetURL); err != nil {
		resp := PreviewResponse{Error: err.Error()}
		writeJSONError(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Prepare HTTP GET request.
	reqHTTP := fasthttp.AcquireRequest()
	resHTTP := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqHTTP)
	defer fasthttp.ReleaseResponse(resHTTP)

	reqHTTP.SetRequestURI(targetURL)
	reqHTTP.Header.SetMethod("GET")
	reqHTTP.Header.SetUserAgent("URLPreviewBot/1.0")

	// Perform the HTTP request with limited redirects.
	if err := defaultClient.DoRedirects(reqHTTP, resHTTP, maxRedirects); err != nil {
		resp := PreviewResponse{Error: fmt.Sprintf("Failed to fetch URL: %v", err)}
		writeJSONError(ctx, resp, fasthttp.StatusBadGateway)
		return
	}

	statusCode := resHTTP.StatusCode()
	if statusCode != fasthttp.StatusOK {
		resp := PreviewResponse{Error: fmt.Sprintf("Unexpected status code: %d", statusCode)}
		writeJSONError(ctx, resp, fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := resHTTP.Body()
	if len(bodyBytes) == 0 {
		resp := PreviewResponse{Error: "Empty response body"}
		writeJSONError(ctx, resp, fasthttp.StatusBadGateway)
		return
	}

	// Limit response size.
	if len(bodyBytes) > maxResponseSize {
		resp := PreviewResponse{Error: "Response body too large"}
		writeJSONError(ctx, resp, fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML for title and description.
	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		resp := PreviewResponse{Error: fmt.Sprintf("Failed to parse HTML: %v", err)}
		writeJSONError(ctx, resp, fasthttp.StatusInternalServerError)
		return
	}

	// Build successful response.
	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(fasthttp.StatusOK)
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		// Logging error is beyond scope, just ignore.
	}
}

// writeJSONError writes a JSON error response with the given status code.
func writeJSONError(ctx *fasthttp.RequestCtx, resp PreviewResponse, statusCode int) {
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(statusCode)
	_ = json.NewEncoder(ctx).Encode(resp)
}

// checkHostAllowed resolves the host of the given URL and ensures it does not resolve to
// a private or disallowed IP address (SSRF protection).
func checkHostAllowed(rawURL string) error {
	u, err := url.Parse(rawURL)
	if err != nil {
		return err
	}
	hostPort := u.Host
	host, _, err := net.SplitHostPort(hostPort)
	if err != nil {
		// Host without port
		host = hostPort
	}

	// Attempt to resolve the hostname to IP addresses.
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("cannot resolve host: %w", err)
	}

	for _, ip := range ips {
		if !isIPAllowed(ip) {
			return fmt.Errorf("host resolves to disallowed IP: %v", ip)
		}
	}
	return nil
}

// isIPAllowed returns true if the IP is considered safe to connect to.
func isIPAllowed(ip net.IP) bool {
	if ip.IsLoopback() {
		return false
	}
	if ip.IsLinkLocalUnicast() {
		return false
	}
	if ip.IsUnspecified() {
		return false
	}

	// IPv4 private ranges.
	if ipv4 := ip.To4(); ipv4 != nil {
		// 10.0.0.0/8
		if ipv4[0] == 10 {
			return false
		}
		// 172.16.0.0/12
		if ipv4[0] == 172 && ipv4[1] >= 16 && ipv4[1] <= 31 {
			return false
		}
		// 192.168.0.0/16
		if ipv4[0] == 192 && ipv4[1] == 168 {
			return false
		}
		// 169.254.0.0/16 (link‑local)
		if ipv4[0] == 169 && ipv4[1] == 254 {
			return false
		}
	}

	// IPv6 unique local (fc00::/7) and link‑local (fe80::/10).
	if ipv6 := ip.To16(); ipv6 != nil {
		if ipv6[0] == 0xfc {
			return false
		}
		if ipv6[0] == 0xfe && ipv6[1] == 0x80 {
			return false
		}
	}

	return true
}

// parseHTMLPreview extracts the <title> content and the meta description (og:description or name=description).
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var foundTitle, foundDesc bool

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if foundTitle && foundDesc {
			return
		}

		if n.Type == html.ElementNode {
			// Extract <title>.
			if !foundTitle && n.Data == "title" {
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						title = strings.TrimSpace(c.Data)
						foundTitle = true
						break
					}
				}
			}

			// Extract <meta name="description"> or <meta property="description">.
			if !foundDesc && n.Data == "meta" {
				var name, prop, content string
