func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse JSON request body
	var req struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.WriteString(`{"error":"invalid request body"}`)
		return
	}
	targetURL := req.URL
	if targetURL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.WriteString(`{"error":"url is required"}`)
		return
	}

	// Prepare request
	freq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(freq)
	freq.SetRequestURI(targetURL)
	freq.Header.SetUserAgent("URLPreview/1.0 (Go)")

	// Prepare response
	fresp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(fresp)

	// Perform the request allowing redirects
	if err := client.DoRedirects(freq, fresp, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.WriteString(fmt.Sprintf(`{"error":"fetch error: %v"}`, err))
		return
	}

	statusCode := fresp.StatusCode()
	if statusCode < 200 || statusCode >= 300 {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.WriteString(fmt.Sprintf(`{"error":"remote responded with status %d"}`, statusCode))
		return
	}

	// Parse HTML
	htmlBody := string(fresp.Body())
	doc, err := html.Parse(strings.NewReader(htmlBody))
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.WriteString(`{"error":"failed to parse HTML"}`)
		return
	}

	// Extract title and meta description
	var title, description string

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// <title>
			if n.Data == "title" && title == "" {
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						title = strings.TrimSpace(c.Data)
						break
					}
				}
			}
			// <meta name="description"> or <meta property="og:description">
			if n.Data == "meta" {
				var name, prop, content string
				for _, a := range n.Attr {
					if a.Key == "name" && a.Val == "description" {
						name = a.Val
					}
					if a.Key == "property" && a.Val == "og:description" {
						prop = a.Val
					}
					if a.Key == "content" {
						content = a.Val
					}
				}
				if (name == "description" || prop == "og:description") && description == "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
		}
	}
	walk(doc)

	// Respond with JSON
	out := map[string]string{
		"title":       title,
		"description": description,
	}
	respJSON, _ := json.Marshal(out)
	ctx.SetContentType("application/json")
	ctx.Write(respJSON)
}

func main() {
	// Start server
	fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		if string(ctx.Method()) == "POST" && string(ctx.Path()) == "/preview" {
			FetchURLPreview(ctx)
		} else {
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.WriteString(`{"error":"not found"}`)
		}
	})
}

