		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts the page title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)
	var titleData []byte
	var descriptionContent string

	for {
		tt := z.Next()
		if tt == html.ErrorToken {
			break
		}
		if tt == html.StartTagToken || tt == html.SelfClosingTagToken {
			t := z.Token()
			if t.Data == "title" {
				// Read the next text token inside <title>
				if tt := z.Next(); tt == html.TextToken {
					titleData = []byte(html.UnescapeString(string(z.Text())))
				}
			} else if t.Data == "meta" {
				var name, prop, content string
				for _, attr := range t.Attr {
					switch attr.Key {
					case "name":
						name = strings.ToLower(attr.Val)
					case "property":
						prop = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				// Look for description meta tag
				if name == "description" || prop == "og:description" {
					descriptionContent = html.UnescapeString(content)
				}
			}
		}
	}

	title = string(titleData)
	description = descriptionContent
	return title, description, nil
}

