// isPrivateIP returns true if the IP is a loopback, link‑local, private or unspecified address.
func isPrivateIP(ip net.IP) bool {
	return ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsUnspecified()
}

// fetchWithSSRFProtection resolves the host of the given URL and ensures it does not
// resolve to a private IP address. It returns the first resolved IP or an error.
func fetchWithSSRFProtection(targetURL string) (net.IP, error) {
	parsedURL, err := url.Parse(targetURL)
	if err != nil {
		return nil, err
	}
	host := parsedURL.Host
	if host == "" {
		return nil, fmt.Errorf("empty host")
	}

	// If the host is already an IP address, check it directly.
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("host resolves to a private IP")
		}
		return ip, nil
	}

	// Perform DNS resolution.
	ips, err := net.LookupIP(host)
	if err != nil {
		// DNS resolution failed – we treat this as a potential SSRF risk and refuse.
		return nil, fmt.Errorf("cannot resolve host: %w", err)
	}
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("host resolves to a private IP")
		}
		// Return the first public IP found.
		return ip, nil
	}
	// No IP returned by LookupIP.
	return nil, fmt.Errorf("no IP found for host")
}

// FetchURLPreview handles POST requests to fetch a URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON body
