// parseHTMLPreview extracts the <title> and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	data, err := io.ReadAll(r)
	if err != nil {
		return "", "", err
	}
	htmlContent := string(data)

	// Simple regex patterns for title and description
	titleRe := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	descRe := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']|<meta[^>]+content=["']([^"']+)["'][^>]+name=["']description["']`)

	// Extract title
