import (
	"encoding/json"
	"regexp"
	"time"

	"github.com/valyala/fasthttp"
)

// Global fasthttp client with required settings.
var (
	client = &fasthttp.Client{
		Dial:         fasthttp.DialTimeout("tcp", 3 * time.Second),
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	// Regex patterns for extracting <title> and meta description.
	titleRe    = regexp.MustCompile(`(?i)<title>([^<]*)</title>`)
	metaDescRe = regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']*)["']`)
)

// FetchURLPreview handles a POST request containing a JSON body with a "url" field.
// It fetches the URL, extracts the page title and meta description, and returns them as JSON.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse JSON body
	var req struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	targetURL := req.URL
	if targetURL == "" {
		ctx.Error("url field is required", fasthttp.StatusBadRequest)
		return
	}

	// Ensure the URL has a scheme
	if !(len(targetURL) >= 4 && (targetURL[:4] == "http" || targetURL[:5] == "https")) {
		targetURL = "http://" + targetURL
	}

	// Reuse request/response objects from the pool
	reqPtr := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(reqPtr)
	respPtr := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(respPtr)

	// Build the GET request
	reqPtr.SetRequestURI(targetURL)
	reqPtr.Header.SetMethod(fasthttp.MethodGet)
	reqPtr.Header.SetUserAgent("Go-URL-Preview/1.0")

	// Perform the request handling redirects
	if err := client.DoRedirects(reqPtr, respPtr, 10); err != nil {
		ctx.Error("failed to fetch URL: "+err.Error(), fasthttp.StatusInternalServerError)
		return
	}

	// Extract HTML body
	body := respPtr.Body()

	// Extract <title>
	title := ""
	if match := titleRe.FindSubmatch(body); len(match) > 1 {
		title = string(match[1])
	}

	// Extract meta description
	desc := ""
	if match := metaDescRe.FindSubmatch(body); len(match) > 1 {
		desc = string(match[1])
	}

	// Build JSON response
	resp := struct {
		URL         string `json:"url"`
		Title       string `json:"title"`
		Description string `json:"description"`
	}{
		URL:         targetURL,
		Title:       title,
		Description: desc,
	}
	respBytes, err := json.Marshal(resp)
	if err != nil {
		ctx.Error("failed to marshal response", fasthttp.StatusInternalServerError)
		return
	}

	ctx.SetContentType("application/json")
	ctx.Write(respBytes)
}

func main() {
	// Start FastHTTP server and route /preview to FetchURLPreview
	if err := fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			if string(ctx.Method()) == fasthttp.MethodPost {
				FetchURLPreview(ctx)
			} else {
				ctx.Error("method not allowed", fasthttp.StatusMethodNotAllowed)
			}
		default:
			ctx.Error("not found", fasthttp.StatusNotFound)
		}
	}); err != nil {
		panic(err)
	}
}

