		parseCIDR("::1/128"),
		parseCIDR("fc00::/7"),
		parseCIDR("fe80::/10"),
	}

	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsUnspecified() {
		return true
	}

	for _, block := range privateIPBlocks {
		if block != nil && block.Contains(ip) {
			return true
		}
	}
	return false
