// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Limit request body size
	body := ctx.PostBody()
	if len(body) > maxRequestBodySize {
		replyError(ctx, "Request body too large", fasthttp.StatusRequestEntityTooLarge)
		return
	}

	var req struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(body, &req); err != nil {
		replyError(ctx, "Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		replyError(ctx, "URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme and format
	parsedURL, err := url.Parse(targetURL)
	if err != nil || parsedURL.Scheme == "" || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		replyError(ctx, "Invalid URL format", fasthttp.StatusBadRequest)
		return
	}
