func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// Read entire content; limit already enforced by client
	data, err := io.ReadAll(r)
	if err != nil {
		return "", "", err
	}
	html := string(data)

	// Extract <title>
	titleRe := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	if m := titleRe.FindStringSubmatch(html); len(m) > 1 {
		title = strings.TrimSpace(m[1])
	}

	// Extract <meta name="description" content="..."> (various orderings)
	metaRe1 := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']`)
	metaRe2 := regexp.MustCompile(`(?i)<meta[^>]+content=["']([^"']+)["'][^>]+name=["']description["']`)

	if m := metaRe1.FindStringSubmatch(html); len(m) > 1 {
		description = strings.TrimSpace(m[1])
	} else if m := metaRe2.FindStringSubmatch(html); len(m) > 1 {
		description = strings.TrimSpace(m[1])
	}

	return title, description, nil
}

