// FetchURLPreview handles POST requests containing a JSON body with a "url" field.
// It fetches the URL, extracts the <title> and <meta name="description"> content,
// and returns them as JSON.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse incoming JSON body
	var reqBody struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		sendError(ctx, "invalid request body")
		return
	}
	if reqBody.URL == "" {
		sendError(ctx, "url is required")
		return
	}

	// Prepare a GET request for the target URL
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqBody.URL)

	// Acquire a response object
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Use DoRedirects to follow redirects (max 10)
	err := client.DoRedirects(req, resp, 10)
	if err != nil {
		sendError(ctx, fmt.Sprintf("failed to fetch URL: %v", err))
		return
	}

	// Check the HTTP status code
	statusCode := resp.StatusCode()
	if statusCode < 200 || statusCode >= 300 {
		sendError(ctx, fmt.Sprintf("remote server returned status %d", statusCode))
		return
	}

	// Extract title and meta description from the fetched HTML
	body := resp.Body()
	title, description := extractMeta(body)

	// Build the JSON response
	respData := ResponseData{
		Title:       title,
		Description: description,
	}
	respBytes, err := json.Marshal(respData)
	if err != nil {
		sendError(ctx, "failed to marshal response")
		return
	}

	ctx.SetContentType("application/json")
	ctx.Write(respBytes)
}

// sendError writes a simple JSON error response.
func sendError(ctx *fasthttp.RequestCtx, msg string) {
	ctx.SetStatusCode(400)
	ctx.SetContentType("application/json")
	jsonMsg, _ := json.Marshal(map[string]string{"error": msg})
	ctx.Write(jsonMsg)
}

// extractMeta extracts the <title> and <meta name="description"> content from HTML.
func extractMeta(html []byte) (title, description string) {
	// Extract <title>...</title>
	titleRe := regexp.MustCompile(`(?i)<title[^>]*>([^<]+)</title>`)
	if m := titleRe.FindSubmatch(html); len(m) > 1 {
		title = trim(string(m[1]))
	}

	// First try: <meta name="description" content="...">
	descRe := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']`)
	if m := descRe.FindSubmatch(html); len(m) > 1 {
		description = trim(string(m[1]))
		return
	}

	// Alternative order: <meta content="..." name="description">
	descReAlt := regexp.MustCompile(`(?i)<meta[^>]+content=["']([^"']+)["'][^>]+name=["']description["']`)
	if m := descReAlt.FindSubmatch(html); len(m) > 1 {
		description = trim(string(m[1]))
	}
	return
}

// trim removes leading and trailing whitespace (including newlines).
func trim(s string) string {
	for len(s) > 0 && (s[0] == ' ' || s[0] == '\t' || s[0] == '\n' || s[0] == '\r') {
		s = s[1:]
	}
	for len(s) > 0 && (s[len(s)-1] == ' ' || s[len(s)-1] == '\t' || s[len(s)-1] == '\n' || s[len(s)-1] == '\r') {
		s = s[:len(s)-1]
	}
	return s
}

// requestHandler routes requests to the appropriate handler.
func requestHandler(ctx *fasthttp.RequestCtx) {
	switch string(ctx.Path()) {
	case "/preview":
		FetchURLPreview(ctx)
	default:
		ctx.Error("Not Found", fasthttp.StatusNotFound)
	}
}

// main registers the FetchURLPreview handler and starts the server.
func main() {
	if err := fasthttp.ListenAndServe(":8080", requestHandler); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

