// It fetches the URL, extracts the <title> and meta description, and returns them as JSON.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON body
	var req urlRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	// Validate presence of URL
	if req.URL == "" {
		ctx.Error("url is required", fasthttp.StatusBadRequest)
		return
	}

	// Parse and validate URL (must have http/https scheme and a host)
	parsedURL, err := url.Parse(req.URL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") || parsedURL.Host == "" {
		ctx.Error("invalid URL", fasthttp.StatusBadRequest)
		return
	}

	// Acquire request and response objects from the pool
	reqObj := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(reqObj)
	respObj := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(respObj)

	// Set the request URI and a custom User-Agent header
	reqObj.SetRequestURI(req.URL)
	reqObj.Header.SetUserAgent("Mozilla/5.0 (compatible; GoPreviewBot/1.0)")

	// Follow redirects using DoRedirects (unlimited redirects with -1)
	if err := previewClient.DoRedirects(reqObj, respObj, -1); err != nil {
		ctx.Error("failed to fetch URL: "+err.Error(), fasthttp.StatusInternalServerError)
		return
	}

	// Extract title and meta description from the fetched HTML
	htmlContent := string(respObj.Body())
	title := extractTitle(htmlContent)
	description := extractMetaDescription(htmlContent)

	// Build response
	resp := previewResponse{
		Title:       title,
		Description: description,
	}

	// Serialize response to JSON
	respBytes, err := json.Marshal(resp)
	if err != nil {
		ctx.Error("failed to marshal response", fasthttp.StatusInternalServerError)
		return
	}

