package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net/url"
	"regexp"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse request JSON body
	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Reusable fasthttp client with timeout and connection settings
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 30 * time.Second,
		MaxConnsPerHost:     10,
	}

	// Acquire request/response objects
	reqHTTP := fasthttp.AcquireRequest()
	respHTTP := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqHTTP)
	defer fasthttp.ReleaseResponse(respHTTP)

	// Prepare GET request
	reqHTTP.SetRequestURI(targetURL)
	reqHTTP.Header.SetMethod("GET")
	reqHTTP.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Follow up to 10 redirects
	if err := client.DoRedirects(reqHTTP, respHTTP, 10); err != nil {
		respondWithError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err))
		return
	}

	if respHTTP.StatusCode() != fasthttp.StatusOK {
		respondWithError(ctx, fmt.Sprintf("Unexpected status code: %d", respHTTP.StatusCode()))
		return
	}

	bodyBytes := respHTTP.Body()
	if len(bodyBytes) == 0 {
		respondWithError(ctx, "Empty response body")
		return
	}

	// Extract title and description from HTML
	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		respondWithError(ctx, fmt.Sprintf("Failed to parse HTML: %v", err))
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

// respondWithError writes a JSON error response and sets an appropriate HTTP status.
func respondWithError(ctx *fasthttp.RequestCtx, message string) {
	resp := PreviewResponse{Error: message}
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(fasthttp.StatusBadGateway)
	_ = json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts the <title> and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	data, err := io.ReadAll(r)
	if err != nil {
		return "", "", err
	}
	html := string(data)

	// <title> tag (case‑insensitive)
	reTitle := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	if match := reTitle.FindStringSubmatch(html); len(match) > 1 {
		title = strings.TrimSpace(match[1])
	}

	// <meta name="description" content="...">
	reDesc := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']`)
	if match := reDesc.FindStringSubmatch(html); len(match) > 1 {
		description = strings.TrimSpace(match[1])
	} else {
		// Alternative order: <meta content="..." name="description">
		reDesc2 := regexp.MustCompile(`(?i)<meta[^>]+content=["']([^"']+)["'][^>]+name=["']description["']`)
		if match := reDesc2.FindStringSubmatch(html); len(match) > 1 {
			description = strings.TrimSpace(match[1])
		}
	}

	return title, description, nil
}

func main() {
	// Start FastHTTP server on port 8080
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		fmt.Println("Server error:", err)
	}
}

