// isPrivateIP checks if an IP address is private or localhost
func isPrivateIP(ip net.IP) bool {
	// Check IPv4 private ranges
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 127.0.0.0/8 (loopback)
		if ip4[0] == 127 {
			return true
		}
		// 169.254.0.0/16 (link-local)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		// 0.0.0.0/8
		if ip4[0] == 0 {
			return true
		}
		// 100.64.0.0/10 (CGN shared address space)
		if ip4[0] == 100 && ip4[1] >= 64 && ip4[1] <= 127 {
			return true
		}
		return false
	}

	// Check IPv6 private ranges
	ip6 := ip.To16()
	if ip6 != nil {
		// ::1 (loopback)
		if ip6[0] == 0 && ip6[1] == 0 && ip6[2] == 0 && ip6[3] == 0 &&
			ip6[4] == 0 && ip6[5] == 0 && ip6[6] == 0 && ip6[7] == 0 &&
			ip6[8] == 0 && ip6[9] == 0 && ip6[10] == 0 && ip6[11] == 0 &&
			ip6[12] == 0 && ip6[13] == 0 && ip6[14] == 0 && ip6[15] == 1 {
			return true
		}
		// fc00::/7 (unique local addresses)
		if ip6[0]&0xfe == 0xfc {
			return true
		}
		// fe80::/10 (link-local)
		if ip6[0] == 0xfe && ip6[1]&0xc0 == 0x80 {
			return true
		}
	}
	return false
}

// isValidTargetURL validates that the URL is safe to fetch
func isValidTargetURL(rawURL string) error {
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL format")
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("URL must use http or https scheme")
	}

	host := parsedURL.Host
	if host == "" {
		return fmt.Errorf("invalid URL: missing host")
	}

	// Check for localhost and similar hosts
	hostLower := strings.ToLower(host)
	if strings.HasPrefix(hostLower, "localhost") ||
		strings.HasPrefix(hostLower, "127.") ||
		strings.HasPrefix(hostLower, "0.") ||
		strings.HasPrefix(hostLower, "10.") ||
		strings.HasPrefix(hostLower, "172.16.") ||
		strings.HasPrefix(hostLower, "172.17.") ||
		strings.HasPrefix(hostLower, "172.18.") ||
		strings.HasPrefix(hostLower, "172.19.") ||
		strings.HasPrefix(hostLower, "172.2") ||
		strings.HasPrefix(hostLower, "172.30.") ||
		strings.HasPrefix(hostLower, "172.31.") ||
		strings.HasPrefix(hostLower, "192.168.") ||
		strings.HasPrefix(hostLower, "169.254.") ||
		hostLower == "::1" ||
		strings.HasPrefix(hostLower, "fc00:") ||
		strings.HasPrefix(hostLower, "fd00:") ||
		strings.HasPrefix(hostLower, "fe80:") {
		return fmt.Errorf("access to localhost or private networks is not allowed")
	}

	// Resolve hostname and check if IP is private
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("cannot resolve hostname")
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	return nil
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Limit request body size to prevent memory exhaustion (max 10MB)
	if len(ctx.PostBody()) > 10*1024*1024 {
		ctx.Error("Request body too large", fasthttp.StatusRequestEntityTooLarge)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL is safe to fetch (prevent SSRF)
	if err := isValidTargetURL(targetURL); err != nil {
		ctx.Error(err.Error(), fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client to fetch with timeout and limits
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     5,
		MaxResponseBodySize: 5 * 1024 * 1024, // Limit response to 5MB
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// Limit redirects to prevent redirect loops
	if err := client.DoRedirects(freq, res, 5); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Validate status code
	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Validate Content-Type is HTML
	contentType := string(res.Header.ContentType())
	if !strings.Contains(contentType, "text/html") && !strings.Contains(contentType, "application/xhtml+xml") {
		ctx.Error("Response is not HTML", fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	// Set security headers
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.Response.Header.Set("X-Content-Type-Options", "nosniff")
	ctx.Response.Header.Set("X-Frame-Options", "DENY")
	ctx.Response.Header.Set("X-XSS-Protection", "1; mode=block")
	ctx.Response.Header.Set("Cache-Control", "no-store, no-cache, must-revalidate, proxy-revalidate, max-age=0")
	ctx.Response.Header.Set("Pragma", "no-cache")
	ctx.Response.Header.Set("Expires", "0")

	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := htmlPkg.Parse(r)
	if err != nil {
		return "", "", err
	}

	// Find title
	var titleNode *htmlPkg.Node
	var findTitle func(*htmlPkg.Node)
	findTitle = func(n *htmlPkg.Node) {
		if n.Type == htmlPkg.ElementNode && n.Data == "title" {
			titleNode = n
			return
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			findTitle(c)
		}
	}
	findTitle(doc)

	if titleNode != nil && titleNode.FirstChild != nil {
		title = titleNode.FirstChild.Data
		title = strings.TrimSpace(title)
		// Limit title length
		if len(title) > 200 {
			title = title[:200]
		}
	}

	// Find meta description
	var findMeta func(*htmlPkg.Node)
	var metaDescription string
	findMeta = func(n *htmlPkg.Node) {
		if n.Type == htmlPkg.ElementNode && n.Data == "meta" {
			var name, content string
			for _, attr := range n.Attr {
				if attr.Key == "name" || attr.Key == "property" {
					if strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
				}
				if attr.Key == "content" {
					content = attr.Val
				}
			}
			if strings.ToLower(name) == "description" {
				metaDescription = content
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			findMeta(c)
		}
	}
	findMeta(doc)

	if metaDescription != "" {
		description = metaDescription
		description = strings.TrimSpace(description)
		// Limit description length
		if len(description) > 500 {
			description = description[:500]
		}
	}

	return title, description, nil
}

