)

// FetchRequest represents the incoming JSON payload.
type FetchRequest struct {
	URL string `json:"url"`
}

// FetchResponse represents the JSON response returned to the client.
type FetchResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests containing a JSON body with a "url" field.
// It fetches the URL, extracts the page title and meta description, and returns them
// as JSON.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse the JSON body
	var req FetchRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeError(ctx, "invalid request body", 400)
		return
	}
	if req.URL == "" {
		writeError(ctx, "url field is required", 400)
		return
	}

	// Validate URL scheme - block dangerous protocols
	if !isValidScheme(req.URL) {
		writeError(ctx, "unsupported URL scheme", 400)
		return
	}

	// Validate URL host - block localhost and private IPs
	if isBlockedHost(req.URL) {
		writeError(ctx, "access to this URL is not allowed", 403)
		return
	}

	// Create a fasthttp client configured to use dual-stack dialing.
	client := &fasthttp.Client{
		DialDualStack: true,
	}

	// Prepare the request
	var reqHTTP fasthttp.Request
	reqHTTP.SetRequestURI(req.URL)
	reqHTTP.Header.SetUserAgent("Go-Fasthttp-Preview/1.0")

	var respHTTP fasthttp.Response

	// Custom Do to track redirects and validate each one
	redirects := 0
	err := client.Do(&reqHTTP, &respHTTP)
	for redirects < 10 {
		statusCode := respHTTP.StatusCode()
		if statusCode >= 300 && statusCode < 400 {
			location := string(respHTTP.Header.Peek("Location"))
			if location == "" {
				break
			}
			// Validate redirect location
			if !isValidScheme(location) {
				writeError(ctx, "unsupported URL scheme in redirect", 403)
				return
			}
			if isBlockedHost(location) {
				writeError(ctx, "access to this URL is not allowed", 403)
				return
			}
			reqHTTP.SetRequestURI(location)
			redirects++
			err = client.Do(&reqHTTP, &respHTTP)
		} else {
			break
		}
	}

	if err != nil {
		writeError(ctx, fmt.Sprintf("failed to fetch URL: %v", err), 500)
		return
