// isValidScheme checks if the URL scheme is http or https
func isValidScheme(url string) bool {
	lowerURL := strings.ToLower(url)
	return strings.HasPrefix(lowerURL, "http://") || strings.HasPrefix(lowerURL, "https://")
}

// isBlockedHost checks if the host is localhost or a private IP
func isBlockedHost(url string) bool {
	// Parse the URL to get the host
	schemeEnd := strings.Index(url, "://")
	if schemeEnd == -1 {
		return true
	}
	hostPort := url[schemeEnd+3:]

	// Remove path
	if slashIdx := strings.Index(hostPort, "/"); slashIdx != -1 {
		hostPort = hostPort[:slashIdx]
	}

	// Remove any fragment or query
	if questionIdx := strings.Index(hostPort, "?"); questionIdx != -1 {
		hostPort = hostPort[:questionIdx]
	}

