	host := hostPort
	if len(host) > 2 && host[0] == '[' {
		if closeBracket := strings.Index(host, "]"); closeBracket != -1 {
			host = host[1:closeBracket]
		}
	} else if colonIdx := strings.Index(host, ":"); colonIdx != -1 {
