}

// isDecimalIP checks if a string is a decimal IP address (IPv4)
func isDecimalIP(host string) bool {
	// Check if it's a valid IPv4 address (all digits and dots)
	parts := strings.Split(host, ".")
	if len(parts) != 4 {
		return false
	}
	for _, part := range parts {
		if _, err := strconv.Atoi(part); err != nil {
