// isPrivateIP checks if an IP is a private or reserved IP
func isPrivateIP(ipStr string) bool {
	ip := net.ParseIP(ipStr)
	if ip == nil {
		return false
	}

	// Check for IPv4 private ranges
	// 10.0.0.0/8
	if ip[0] == 10 {
