	// fe80::/10 (link-local)
	if len(ip) == 16 && ip[0] == 0xfe && (ip[1]&0xc0) == 0x80 {
		return true
	}
	// fd00::/8
	if len(ip) == 16 && ip[0] == 0xfd {
		return true
	}

	// Check for IPv4-mapped IPv6 addresses (::ffff:0:0/96)
	if len(ip) == 16 && ip[0] == 0 && ip[1] == 0 && ip[2] == 0 && ip[3] == 0 && ip[4] == 0 && ip[5] == 0 && ip[6] == 0 && ip[7] == 0 && ip[8] == 0 && ip[9] == 0 && ip[10] == 0xff && ip[11] == 0xff {
		// Check the IPv4 part for private IPs
		v4ip := net.IP(ip[12:16])
		if isPrivateIP(v4ip.String()) {
			return true
		}
	}

	return false
}

// writeError sends a JSON error response.
func writeError(ctx *fasthttp.RequestCtx, errMsg string, statusCode int) {
	resp := FetchResponse{Error: errMsg}
	respBytes, _ := json.Marshal(resp)
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(statusCode)
	ctx.Write(respBytes)
}

// extractMeta extracts the <title> and the content of
// <meta name="description" content="..."> from the HTML.
func extractMeta(html []byte) (title, description string) {
	// Match <title>...</title>
	titleRe := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	if m := titleRe.FindSubmatch(html); len(m) > 1 {
		title = string(m[1])
	}

	// Match <meta name="description" content="..."> (order independent)
	descRe := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']`)
	if m := descRe.FindSubmatch(html); len(m) > 1 {
		description = string(m[1])
		return
	}
	// Try the alternative attribute order: <meta content="..." name="description">
	descRe2 := regexp.MustCompile(`(?i)<meta[^>]+content=["']([^"']+)["'][^>]+name=["']description["']`)
	if m := descRe2.FindSubmatch(html); len(m) > 1 {
		description = string(m[1])
	}

	return
}

func main() {
	// Start the fasthttp server on port 8080
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		fmt.Printf("error starting server: %v\n", err)
	}
}

