// parseHTMLPreview extracts the <title> and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var (
		titleFound     bool
		descriptionSet bool
	)

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract <title>
			if !titleFound && n.Data == "title" {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
					titleFound = true
				}
			}

			// Extract meta description (name="description" or property="og:description")
			if !descriptionSet && n.Data == "meta" {
				var nameAttr, propAttr, contentAttr string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						nameAttr = strings.ToLower(attr.Val)
					case "property":
						propAttr = strings.ToLower(attr.Val)
					case "content":
						contentAttr = attr.Val
					}
				}
				if (nameAttr == "description" || propAttr == "og:description") && contentAttr != "" {
					description = strings.TrimSpace(contentAttr)
					descriptionSet = true
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
		}
	}

	walk(doc)
	return title, description, nil
}

