package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// maxResponseSize limits the number of bytes read from the remote server.
// 2 MB.
const maxResponseSize = 2 << 20

// globalClient is a reusable HTTP client with timeouts and connection limits.
var globalClient = &fasthttp.Client{
	Dial:                fasthttp.DialDualStack,
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 30 * time.Second,
	MaxConnsPerHost:     10,
	// MaxRedirectsCount is set per request via DoRedirects.
}

// isPrivateIP reports whether an IP address is private or reserved.
// It supports both IPv4 and IPv6.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() {
		return true
	}
	if ip.IsUnspecified() {
		return true
	}
	// 10.0.0.0/8
	if ip[0] == 10 {
		return true
	}
	// 172.16.0.0/12
	if ip[0] == 172 && ip[1] >= 16 && ip[1] <= 31 {
		return true
	}
	// 192.168.0.0/16
	if ip[0] == 192 && ip[1] == 168 {
		return true
	}
	// 169.254.0.0/16 (link‑local)
	if ip[0] == 169 && ip[1] == 254 {
		return true
	}
	// IPv6 unique local (fc00::/7) and link‑local (fe80::/10)
	if ip[0] == 0xfc {
		return true
	}
	if ip[0] == 0xfe && ip[1] >= 0x80 {
		return true
	}
	return false
}

// resolveHostToIP attempts to resolve a hostname to an IP address.
// It returns the first IP found or an error if resolution fails.
func resolveHostToIP(host string) (net.IP, error) {
	// If the host is already an IP, parse it directly.
	ip := net.ParseIP(host)
	if ip != nil {
		return ip, nil
	}
	// DNS resolution.
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, fmt.Errorf("dns resolution failed: %w", err)
	}
	if len(ips) == 0 {
		return nil, fmt.Errorf("no IP found for host")
	}
	return ips[0], nil
}

// isURLAllowed validates that a URL points to a public resource and
// does not refer to private networks (SSRF protection).
func isURLAllowed(rawURL string) error {
	u, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL: %w", err)
	}
	if u.Scheme != "http" && u.Scheme != "https" {
		return fmt.Errorf("unsupported scheme")
	}
	if u.Host == "" {
		return fmt.Errorf("empty host")
	}
	// Reject userinfo (e.g., http://user:pass@host)
	if u.User != nil {
		return fmt.Errorf("userinfo not allowed")
	}
	// Resolve host to an IP and verify it's not private.
	ip, err := resolveHostToIP(u.Host)
	if err != nil {
		return fmt.Errorf("cannot resolve host: %w", err)
	}
	if isPrivateIP(ip) {
		return fmt.Errorf("host resolves to private IP")
	}
	return nil
}

// FetchURLPreview handles POST requests to fetch a URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if len(body) == 0 {
		ctx.Error("Missing request body", fasthttp.StatusBadRequest)
		return
	}

	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL for SSRF risks.
	if err := isURLAllowed(targetURL); err != nil {
		ctx.Error(fmt.Sprintf("URL not allowed: %v", err), fasthttp.StatusBadRequest)
		return
	}

	// Reuse a single request/response buffer.
	reqHTTP := fasthttp.AcquireRequest()
	resHTTP := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqHTTP)
	defer fasthttp.ReleaseResponse(resHTTP)

	reqHTTP.SetRequestURI(targetURL)
	reqHTTP.Header.SetMethod("GET")
	reqHTTP.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Perform the HTTP request with a limited number of redirects.
	if err := globalClient.DoRedirects(reqHTTP, resHTTP, 5); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	statusCode := resHTTP.StatusCode()
	if statusCode != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", statusCode), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := resHTTP.Body()

	// Enforce maximum response size to prevent memory exhaustion.
	if len(bodyBytes) > maxResponseSize {
		ctx.Error("Response too large", fasthttp.StatusBadGateway)
		return
	}

	// After redirects, verify the final location is still allowed.
	finalURL := reqHTTP.URI().String()
	if err := isURLAllowed(finalURL); err != nil {
		ctx.Error(fmt.Sprintf("Redirect target not allowed: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML for title and meta description.
	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		// Failing to write the response is unlikely but we handle it.
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

