// It fetches the URL, extracts the <title> and <meta name="description"> content,
// and returns a JSON response containing those values.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse the JSON body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		fmt.Fprintf(ctx, `{"error":"invalid request body"}`)
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		fmt.Fprintf(ctx, `{"error":"url is required"}`)
		return
	}

	// Build the request to the target URL
	var reqHTTP fasthttp.Request
	reqHTTP.SetRequestURI(req.URL)

	// Perform the HTTP request with redirect handling
	var resp fasthttp.Response
	if err := previewClient.DoRedirects(&reqHTTP, &resp, 0); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		fmt.Fprintf(ctx, `{"error":"failed to fetch URL: %v"}`, err)
		return
	}

	// Extract title and meta description from the response body
	body := resp.Body()
	title, description := extractMeta(body)

	// Build and send JSON response
	response := Response{
		Title:       title,
		Description: description,
	}
	respBody, err := json.Marshal(response)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		fmt.Fprintf(ctx, `{"error":"failed to marshal response"}`)
		return
	}

	ctx.SetContentType("application/json")
	ctx.Write(respBody)
}

// extractMeta extracts the <title> tag content and the content of
// <meta name="description" content="..."> from an HTML document.
func extractMeta(html []byte) (title, description string) {
	s := string(html)
	lower := strings.ToLower(s)

	// --- Title ---
	startTitle := strings.Index(lower, "<title>")
	if startTitle != -1 {
		startTitle += len("<title>")
		endTitle := strings.Index(lower[startTitle:], "</title>")
		if endTitle != -1 {
			title = s[startTitle : startTitle+endTitle]
		}
	}

	// --- Meta description ---
	descIdx := strings.Index(lower, `name="description"`)
	if descIdx != -1 {
		// Find the content attribute after the name
		contentStart := strings.Index(lower[descIdx:], `content="`)
		if contentStart != -1 {
			contentStart += len(`content="`)
			contentEnd := strings.Index(lower[descIdx+contentStart:], `"`)
			if contentEnd != -1 {
				description = s[descIdx+contentStart : descIdx+contentStart+contentEnd]
			}
		}
	}

	return title, description
}

