var client = fasthttp.Client{
	Dial:         fasthttp.DialDualStack,
	ReadTimeout:  10 * time.Second,
	WriteTimeout: 10 * time.Second,
}

// FetchURLPreview handles POST requests with a JSON body containing a "url" field.
// It fetches the URL, extracts the page title and meta description, and returns a JSON response.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse JSON request body
	var reqBody struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		writeError(ctx, "invalid request body")
		return
	}
	if reqBody.URL == "" {
		writeError(ctx, "url field is required")
		return
	}

	// Prepare HTTP GET request
	req := fasthttp.Request{}
	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod("GET")
	req.Header.SetUserAgent("URLPreviewBot/1.0")

	// Perform request following redirects (up to 10 hops)
	resp := fasthttp.Response{}
	if err := client.DoRedirects(&req, &resp, 10); err != nil {
		writeError(ctx, "failed to fetch URL: "+err.Error())
		return
	}

	// Extract title and description from HTML
	html := string(resp.Body())
	title, description := extractMeta(html)

	// Return JSON response
	respJSON, err := json.Marshal(map[string]string{
		"title":       title,
		"description": description,
	})
	if err != nil {
		writeError(ctx, "failed to marshal response")
		return
	}
	ctx.SetContentType("application/json")
	ctx.Write(respJSON)
}

// extractMeta parses the HTML and returns the title and meta description.
func extractMeta(html string) (title, description string) {
	// Extract <title>
	titleRe := regexp.MustCompile(`(?i)<title[^>]*>([^<]+)</title>`)
	if m := titleRe.FindStringSubmatch(html); len(m) > 1 {
		title = m[1]
	}

	// Extract <meta name="description" content="..."> (two possible attribute orders)
	descRe1 := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']`)
	descRe2 := regexp.MustCompile(`(?i)<meta[^>]+content=["']([^"']+)["'][^>]+name=["']description["']`)

	if m := descRe1.FindStringSubmatch(html); len(m) > 1 {
		description = m[1]
	} else if m := descRe2.FindStringSubmatch(html); len(m) > 1 {
		description = m[1]
	}
	return
}

// writeError writes a JSON error response and sets the status code to 400.
func writeError(ctx *fasthttp.RequestCtx, msg string) {
	respJSON, _ := json.Marshal(map[string]string{"error": msg})
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusBadRequest)
	ctx.Write(respJSON)
}

func main() {
	// Start FastHTTP server on port 8080
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		panic(err)
	}
}

