package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net/url"
	"regexp"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// client is a reusable fasthttp client.
var client = &fasthttp.Client{
	Dial:                fasthttp.DialDualStack,
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 10 * time.Second,
	MaxConnsPerHost:     10,
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Build request
	reqHTTP := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqHTTP)
	defer fasthttp.ReleaseResponse(res)

	reqHTTP.SetRequestURI(targetURL)
	reqHTTP.Header.SetMethod("GET")
	reqHTTP.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirects := 10
	if err := client.DoRedirects(reqHTTP, res, maxRedirects); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	statusCode := res.StatusCode()
	if statusCode != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", statusCode), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	data, err := io.ReadAll(r)
	if err != nil {
		return "", "", fmt.Errorf("reading HTML: %w", err)
	}
	html := string(data)

	// Extract <title>
	titleRe := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	if matches := titleRe.FindStringSubmatch(html); len(matches) > 1 {
		title = strings.TrimSpace(matches[1])
	}

	// Try Open Graph description first
	ogDescRe := regexp.MustCompile(`(?i)<meta[^>]+property=["']og:description["'][^>]+content=["']([^"']*)["']`)
	if matches := ogDescRe.FindStringSubmatch(html); len(matches) > 1 {
		description = strings.TrimSpace(matches[1])
	} else {
		// Fallback to name="description"
		nameDescRe := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']*)["']`)
		if matches := nameDescRe.FindStringSubmatch(html); len(matches) > 1 {
			description = strings.TrimSpace(matches[1])
		} else {
			// Alternate order: content before name
			altDescRe := regexp.MustCompile(`(?i)<meta[^>]+content=["']([^"']*)["'][^>]+name=["']description["']`)
			if matches := altDescRe.FindStringSubmatch(html); len(matches) > 1 {
				description = strings.TrimSpace(matches[1])
			}
		}
	}

	return title, description, nil
}

func main() {
	// Register handler and start server.
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

