// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// httpClient is a shared fasthttp client with timeouts and a max response size.
// It is safe for concurrent use.
var httpClient = &fasthttp.Client{
	Dial:                fasthttp.DialDualStack,
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 30 * time.Second,
	MaxConnsPerHost:     10,
	MaxResponseBodySize: 2 * 1024 * 1024, // limit response body to 2 MiB
}

// maxRedirects limits the number of followed redirects.
const maxRedirects = 10

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON body
	var req struct {
		URL string `json:"url"`
	}
	body := ctx.PostBody()
	if len(body) == 0 {
		ctx.Error("Request body is empty", fasthttp.StatusBadRequest)
		return
	}
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(targetURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Prevent Server-Side Request Forgery (SSRF) by blocking private / loopback IPs
	host := parsedURL.Hostname()
	if err := validateHost(host); err != nil {
		ctx.Error(err.Error(), fasthttp.StatusBadRequest)
		return
	}

	// Prepare request
	freq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(freq)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.SetUserAgent("URLPreviewBot/1.0")

	// Acquire response and release it after use
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(res)

	// Perform the HTTP request with redirect handling
	if err := httpClient.DoRedirects(freq, res, maxRedirects); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Check status code
	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Ensure we have a body (response size is already limited by the client)
	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Extract title and description from HTML
	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Build JSON response
	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

// validateHost ensures the given host does not resolve to a private or loopback IP.
func validateHost(host string) error {
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("cannot resolve host: %w", err)
	}
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("host resolves to a private or loopback IP")
		}
	}
	return nil
}

// isPrivateIP returns true if the IP is loopback, link‑local or in a private range.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() {
		return true
	}
	if ip.IsLinkLocalUnicast() {
		return true
	}
	if ip.IsPrivate() {
		return true
	}
	// Optionally block other known private ranges (e.g., 169.254.169.254 for cloud metadata)
	return false
}

// parseHTMLPreview extracts the <title> and meta description from HTML.
// It limits the amount of data read to 1 MiB to avoid huge allocations.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// Limit the reader to 1 MiB to avoid reading huge HTML pages.
	limitedReader := io.LimitReader(r, 1<<20)
	data, err := io.ReadAll(limitedReader)
	if err != nil {
		return "", "", err
	}
	html := string(data)

	// Extract <title> content (case‑insensitive)
	reTitle := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	if matches := reTitle.FindStringSubmatch(html); len(matches) > 1 {
		title = strings.TrimSpace(matches[1])
	}

	// Extract <meta name="description" content="..."> (support different attribute orders)
	reDesc := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)[^>]*>`)
	if matches := reDesc.FindStringSubmatch(html); len(matches) > 1 {
		description = strings.TrimSpace(matches[1])
	} else {
		// Try reversed attribute order: <meta content="..." name="description">
		reDesc2 := regexp.MustCompile(`(?i)<meta[^>]+content=["']([^"']+)[^>]+name=["']description["']>`)
		if matches := reDesc2.FindStringSubmatch(html); len(matches) > 1 {
			description = strings.TrimSpace(matches[1])
		}
	}

	return title, description, nil
}

