package main

import (
	"encoding/json"
	"net/url"
	"regexp"

	"github.com/valyala/fasthttp"
)

// Global HTTP client with DialDualStack set as required.
var client = fasthttp.Client{
	Dial: fasthttp.DialDualStack,
}

// FetchURLPreview handles POST requests containing a JSON body with a "url" field,
// fetches the URL, extracts the <title> and <meta name="description"> (or og:description)
// and returns a JSON response.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if string(ctx.Method()) != "POST" {
		ctx.Response.SetStatusCode(405)
		ctx.Response.SetBodyString(`{"error":"method not allowed"}`)
		return
	}

	// Parse JSON body
	var req struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.Request.Body(), &req); err != nil {
		ctx.Response.SetStatusCode(400)
		ctx.Response.SetBodyString(`{"error":"invalid JSON"}`)
		return
	}

	if req.URL == "" {
		ctx.Response.SetStatusCode(400)
		ctx.Response.SetBodyString(`{"error":"url is required"}`)
		return
	}

	// Normalize URL (add http:// if scheme missing)
	parsedURL, err := url.Parse(req.URL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		// Try with http scheme
		withScheme := "http://" + req.URL
		parsedURL, err = url.Parse(withScheme)
		if err != nil {
			ctx.Response.SetStatusCode(400)
			ctx.Response.SetBodyString(`{"error":"invalid URL"}`)
			return
		}
		req.URL = withScheme
	}

	// Prepare GET request
	var request fasthttp.Request
	request.SetRequestURI(req.URL)
	request.Header.SetMethod("GET")

	var response fasthttp.Response

	// Use DoRedirects as required
	const maxRedirects = 10
	if err := client.DoRedirects(&request, &response, maxRedirects); err != nil {
		ctx.Response.SetStatusCode(502)
		ctx.Response.SetBodyString(`{"error":"failed to fetch URL"}`)
		return
	}

	// Extract title and meta description from the fetched HTML
	title, description := extractTitleAndDescription(response.Body())

	// Build JSON response
	resp := struct {
		Title       string `json:"title"`
		Description string `json:"description"`
		URL         string `json:"url"`
	}{
		Title:       title,
		Description: description,
		URL:         req.URL,
	}

	respBytes, _ := json.Marshal(resp)
	ctx.Response.SetStatusCode(200)
	ctx.Response.Header.SetContentType("application/json")
	ctx.Response.SetBody(respBytes)
}

// extractTitleAndDescription parses HTML bytes and returns the page title
// and the content of the meta description tag (name="description" or property="og:description").
func extractTitleAndDescription(body []byte) (title, description string) {
	// Extract <title>
	reTitle := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	if m := reTitle.FindSubmatch(body); len(m) > 1 {
		title = string(m[1])
	}

	// Try <meta name="description" content="...">
	reDesc1 := regexp.MustCompile(`(?i)<meta\s+(?:name|property)=["']description["']\s+content=["']([^"']+)["']`)
	// Try <meta content="..." name="description"> (reversed order)
	reDesc2 := regexp.MustCompile(`(?i)<meta\s+content=["']([^"']+)["']\s+(?:name|property)=["']description["']`)

	if m := reDesc1.FindSubmatch(body); len(m) > 1 {
		description = string(m[1])
	} else if m := reDesc2.FindSubmatch(body); len(m) > 1 {
		description = string(m[1])
	}

	return title, description
}

func main() {
	// Start FastHTTP server on port 8080
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		panic(err)
	}
}

