// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("url is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL and scheme
	parsedURL, err := url.Parse(targetURL)
	if err != nil {
		ctx.Error("invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("url must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Prepare request
	reqHTTP := fasthttp.AcquireRequest()
	resHTTP := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqHTTP)
	defer fasthttp.ReleaseResponse(resHTTP)

	reqHTTP.SetRequestURI(targetURL)
	reqHTTP.Header.SetMethod("GET")
	reqHTTP.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Perform request with redirects
	if err := httpClient.DoRedirects(reqHTTP, resHTTP, 10); err != nil {
		ctx.Error(fmt.Sprintf("failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if resHTTP.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("unexpected status code: %d", resHTTP.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := resHTTP.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Build JSON response
	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts the <title> and meta description from an HTML document.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var dfs func(*html.Node)
	dfs = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, prop, content string
				for _, a := range n.Attr {
					switch a.Key {
					case "name":
						name = strings.ToLower(a.Val)
					case "property":
						prop = strings.ToLower(a.Val)
					case "content":
						content = a.Val
					}
				}
				if name == "description" || prop == "og:description" {
					description = strings.TrimSpace(content)
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			dfs(c)
		}
	}
	dfs(doc)
	return title, description, nil
}

// main starts a fasthttp server and registers the FetchURLPreview handler.
func main() {
	// Simple router that forwards /preview to FetchURLPreview.
	fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("not found", fasthttp.StatusNotFound)
		}
	})
}

