	// Only accept POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Enforce JSON content type (allow charset)
	ctype := string(ctx.Request.Header.ContentType())
	if !strings.Contains(strings.ToLower(ctype), "application/json") {
		ctx.Error("Content-Type must be application/json", fasthttp.StatusUnsupportedMediaType)
		return
	}

	// Read and limit request body
	body := ctx.PostBody()
	if len(body) > maxRequestBodySize {
		ctx.Error("Request body too large", fasthttp.StatusRequestEntityTooLarge)
		return
	}

	var req struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	scheme := strings.ToLower(parsedURL.Scheme)
	if scheme != "http" && scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Extract hostname (without port) for SSRF checks
	host := parsedURL.Hostname()
	if host == "" {
		ctx.Error("Invalid URL: missing host", fasthttp.StatusBadRequest)
		return
	}

	// SSRF protection: block private/loopback IPs
	if !isHostAllowed(host) {
		ctx.Error("Access to this host is denied", fasthttp.StatusForbidden)
		return
	}

	// Prepare request object
	reqObj := fasthttp.AcquireRequest()
	resObj := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqObj)
	defer fasthttp.ReleaseResponse(resObj)

	reqObj.SetRequestURI(targetURL)
	reqObj.Header.SetMethod("GET")
	reqObj.Header.SetUserAgent("URLPreviewBot/1.0")

	// Perform the HTTP request
	if err := previewClient.Do(reqObj, resObj); err != nil {
		ctx.Error("Failed to fetch URL", fasthttp.StatusBadGateway)
		return
	}

	// Check status code
	if resObj.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Remote server returned status %d", resObj.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Limit response size
	bodyBytes := resObj.Body()
	if len(bodyBytes) > maxResponseBodySize {
		ctx.Error("Response body too large", fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML to extract title and description
	title, description, err := parseHTMLPreview(bodyBytes)
	if err != nil {
		ctx.Error("Failed to parse HTML", fasthttp.StatusInternalServerError)
		return
	}

	// Build JSON response
	resp := PreviewResponse{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

// isHostAllowed checks if the given host is a private IP address.
// If the host is not an IP address (i.e., a domain), the function returns true.
// It blocks loopback, private, link‑local, and unspecified addresses.
func isHostAllowed(host string) bool {
	// Try to parse as an IP address
	ip := net.ParseIP(host)
	if ip == nil {
		// Not an IP – allow for now (could add more domain checks if needed)
		return true
	}
	// Reject any private, loopback, link‑local, or unspecified address
	if ip.IsPrivate() || ip.IsLoopback() || ip.IsUnspecified() || ip.IsLinkLocalUnicast() {
		return false
	}
	return true
}

// Pre‑compiled regular expressions for HTML parsing.
var (
	titleRe = regexp.MustCompile(`(?i)<title[^>]*>([^<]+)</title>`)
	// Matches <meta name="description" content="..."> or <meta property="description" content="...">
	metaDescRe = regexp.MustCompile(`(?i)<meta[^>]+(?:name|property)=["']description["'][^>]*content=["']([^"']+)["']`)
	// Matches <meta property="og:description" content="...">
	ogDescRe = regexp.MustCompile(`(?i)<meta[^>]+property=["']og:description["'][^>]*content=["']([^"']+)["']`)
)

// parseHTMLPreview extracts the <title> and meta description from the HTML body.
// It returns empty strings if the elements are not found.
func parseHTMLPreview(data []byte) (title, description string, err error) {
	// Extract title
	m := titleRe.FindSubmatch(data)
	if len(m) > 1 {
		title = string(m[1])
	}

	// Try to find description: first standard meta tag, then OpenGraph
	m = metaDescRe.FindSubmatch(data)
	if len(m) > 1 {
		description = string(m[1])
	} else {
		m = ogDescRe.FindSubmatch(data)
		if len(m) > 1 {
			description = string(m[1])
		}
	}
	return title, description, nil
}

// main sets up a simple HTTP server that routes /preview to FetchURLPreview.
func main() {
	// Simple router
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}

	// Configure server timeouts for extra safety
	s := &fasthttp.Server{
		ReadTimeout:  5 * time.Second,
		WriteTimeout: 5 * time.Second,
		IdleTimeout:  30 * time.Second,
		Handler:      handler,
	}

	// Listen on port 8080
	if err := s.ListenAndServe(":8080"); err != nil {
		fmt.Println("Server error:", err)
	}
}

