	Description string `json:"description"`
}

// Precompiled regular expressions for HTML parsing.
var (
	titleRe = regexp.MustCompile(`(?i)<title>(?P<title>[^<]+)</title>`)
	// Matches <meta name="description" content="..."> or <meta content="..." name="description">
	// and also <meta property="og:description" content="...">
	metaDescRe = regexp.MustCompile(`(?i)<meta[^>]+(?:name|property)=["']description["'][^>]+content=["'](?P<desc>[^"']+)["']|<meta[^>]+content=["'](?P<desc>[^"']+)["'][^>]+(?:name|property)=["']description["']`)
)

// Global fasthttp client with dual-stack dial.
var client = &fasthttp.Client{
	Dial: fasthttp.DialDualStack,
}

// FetchURLPreview handles POST requests with a JSON body {"url":"..."}.
// It fetches the URL, extracts the <title> and meta description, and returns a JSON response.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse JSON body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.Write([]byte(`{"error":"invalid JSON body"}`))
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.Write([]byte(`{"error":"url field is required"}`))
		return
	}

	// Ensure the URL has a scheme; default to http if missing.
	if !strings.HasPrefix(req.URL, "http://") && !strings.HasPrefix(req.URL, "https://") {
		req.URL = "http://" + req.URL
	}

	// Prepare GET request
	httpReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(httpReq)
	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod("GET")

	// Prepare response object
	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(httpResp)

	// Perform request following redirects (max 10)
	if err := client.DoRedirects(httpReq, httpResp, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetContentType("application/json")
		ctx.Write([]byte(`{"error":"failed to fetch URL"}`))
		return
	}

	// Extract HTML body
	body := httpResp.Body()

	// Extract <title>
	title := ""
	if match := titleRe.FindSubmatch(body); len(match) > 1 {
		title = string(match[1])
	}

	// Extract meta description
	description := ""
	if match := metaDescRe.FindSubmatch(body); len(match) > 1 {
		description = string(match[1])
	}

	// Build response
	resp := Response{
		Title:       title,
		Description: description,
	}
	respBytes, _ := json.Marshal(resp)

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	ctx.Write(respBytes)
}

func main() {
	// Register the handler under /preview and start the server.
	fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
