// isPrivateIP checks if the IP is a private/reserved IP address
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsUnspecified() || ip.IsLinkLocalUnicast() {
		return true
	}
	// Check for private ranges
	privateIPBlocks := []*net.IPNet{
		parseCIDR("10.0.0.0/8"),
		parseCIDR("172.16.0.0/12"),
		parseCIDR("192.168.0.0/16"),
		parseCIDR("169.254.0.0/16"), // Link-local
		parseCIDR("127.0.0.0/8"),    // Loopback
	}
	for _, block := range privateIPBlocks {
		if block != nil && block.Contains(ip) {
			return true
		}
	}
	return false
}

func parseCIDR(cidr string) *net.IPNet {
	_, ipNet, _ := net.ParseCIDR(cidr)
	return ipNet
}

// validateURL validates the URL for security concerns (SSRF protection)
func validateURL(rawURL string) error {
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL: %v", err)
	}

	host := parsedURL.Host
	if host == "" {
		return fmt.Errorf("empty host")
	}

	// Try to resolve the hostname
	ips, err := net.LookupIP(host)
	if err != nil {
		// Don't fail on DNS errors, but log them
		return fmt.Errorf("cannot resolve hostname: %v", err)
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	return nil
}

