// FetchURLPreview handles POST requests with a JSON {"url": "..."}
// and returns a JSON response containing the page title and meta description.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse JSON body
	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		respondError(ctx, "invalid request body")
		return
	}

	if req.URL == "" {
		respondError(ctx, "url field is required")
		return
	}

	// Normalize URL to ensure it has a scheme
	urlStr := req.URL
	if !strings.HasPrefix(urlStr, "http://") && !strings.HasPrefix(urlStr, "https://") {
		urlStr = "http://" + urlStr
	}

	// Build the GET request
	var reqHTTP fasthttp.Request
	reqHTTP.SetRequestURI(urlStr)
	reqHTTP.Header.SetMethod(fasthttp.MethodGet)

	// Perform the request, following up to 10 redirects
	var respHTTP fasthttp.Response
	if err := fetchClient.DoRedirects(&reqHTTP, &respHTTP, 10); err != nil {
		respondError(ctx, fmt.Sprintf("failed to fetch URL: %v", err))
		return
	}

	// Only accept 2xx responses
	statusCode := respHTTP.StatusCode()
	if statusCode < 200 || statusCode >= 300 {
		respondError(ctx, fmt.Sprintf("unexpected status code: %d", statusCode))
		return
	}

	// Extract title and meta description from the HTML body
	body := respHTTP.Body()
	title, description := extractMeta(body)

	resp := URLResponse{
		Title:       title,
		Description: description,
	}

	respBytes, err := json.Marshal(resp)
	if err != nil {
		respondError(ctx, "failed to marshal response")
		return
	}

	ctx.SetContentType("application/json")
	ctx.Write(respBytes)
}

// respondError writes a JSON error response and sets the status code to 400.
func respondError(ctx *fasthttp.RequestCtx, message string) {
	errResp := ErrorResponse{Error: message}
	respBytes, _ := json.Marshal(errResp) // ignoring error as we are already in error path
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusBadRequest)
	ctx.Write(respBytes)
}

// extractMeta parses the HTML and returns the page title and meta description.
func extractMeta(htmlContent []byte) (title, description string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return
	}

	var find func(*html.Node)
	find = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" {
				// Collect all text inside <title>
				var buf bytes.Buffer
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						buf.WriteString(c.Data)
					}
				}
				title = strings.TrimSpace(buf.String())
			} else if n.Data == "meta" {
