package main

import (
	"encoding/json"
	"fmt"
	"regexp"
	"strings"

	"github.com/valyala/fasthttp"
)

// Client is reused for making HTTP requests.
var client = fasthttp.Client{
	// Set Dial to DualStack to handle both IPv4 and IPv6.
	Dial: fasthttp.DialDualStack,
}

// FetchURLPreview handles POST requests with a JSON body containing a "url" field.
// It fetches the URL, extracts the page title and meta description, and returns a JSON response.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse the request body into a simple struct.
	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		sendError(ctx, "invalid request body")
		return
	}

	if req.URL == "" {
		sendError(ctx, "url is required")
		return
	}

	// Build the GET request.
	var fasthttpReq fasthttp.Request
	fasthttpReq.SetRequestURI(req.URL)
	fasthttpReq.Header.SetMethod("GET")
	fasthttpReq.Header.SetUserAgent("Go-Fasthttp-URLPreview/1.0")

	var fasthttpResp fasthttp.Response

	// Use DoRedirects to follow redirects (max 10).
	err := client.DoRedirects(&fasthttpReq, &fasthttpResp, 10)
	if err != nil {
		sendError(ctx, fmt.Sprintf("failed to fetch URL: %v", err))
		return
	}

	html := strings.TrimSpace(string(fasthttpResp.Body()))

	title, description := extractMetadata(html)

	// Build the response.
	resp := struct {
		Title       string `json:"title"`
		Description string `json:"description"`
		Error       string `json:"error,omitempty"`
	}{
		Title:       title,
		Description: description,
	}

	respBytes, err := json.Marshal(resp)
	if err != nil {
		sendError(ctx, "failed to marshal response")
		return
	}

	ctx.SetContentType("application/json")
	ctx.Write(respBytes)
}

// extractMetadata extracts the <title> and meta description from the HTML string.
// It uses simple regular expressions for portability.
func extractMetadata(html string) (title, description string) {
	// Extract <title>...</title>
	titleRe := regexp.MustCompile(`(?i)<title[^>]*>([^<]+)</title>`)
	if matches := titleRe.FindStringSubmatch(html); len(matches) > 1 {
		title = strings.TrimSpace(matches[1])
	}

	// Extract <meta name="description" content="...">
	// This regex handles variations in attribute order and quote style.
	descRe := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']`)
	if matches := descRe.FindStringSubmatch(html); len(matches) > 1 {
		description = strings.TrimSpace(matches[1])
	}

	return
}

// sendError writes a JSON error response.
func sendError(ctx *fasthttp.RequestCtx, message string) {
	resp := struct {
		Error string `json:"error"`
	}{Error: message}
	bytes, _ := json.Marshal(resp)
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusBadRequest)
	ctx.Write(bytes)
}

func main() {
	// Register the handler.
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

